# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string
import html
import re

app = Flask(__name__)

def escape_allow_basic_formatting(value: str) -> str:
    if value is None:
        return ""
    escaped = html.escape(value, quote=True)
    escaped = re.sub(r"\*\*(.+?)\*\*", r"<strong>\1</strong>", escaped, flags=re.DOTALL)
    escaped = re.sub(r"\*(.+?)\*", r"<em>\1</em>", escaped, flags=re.DOTALL)
    escaped = escaped.replace("\n", "<br>")
    return escaped

@app.route("/dashboard")
def dashboard():
    name = html.escape(request.args.get("name", "Guest"), quote=True)
    location = html.escape(request.args.get("location", "Unknown"), quote=True)
    bio = escape_allow_basic_formatting(request.args.get("bio", "No bio provided."))
    status = escape_allow_basic_formatting(request.args.get("status", "Ready to explore the dashboard."))

